var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"학회장이 고용한 뜨내기라더니……. 확실히 흥미로운 연구 대상이구려.","JPN":"学会長が雇った流れ者だと聞いたが……確かに興味深い研究対象だ。","ENG":"I heard you were some goon hired by the President... But you truly are an interesting subject.","TWN":"聽說你是學會長雇傭的新人……確實是個有趣的研究物件呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"자료로만 봤던 맨션의 암살자도 이 정도 수준일지, 궁금해지는군.","JPN":"資料でした見たことのないマンションの暗殺者もこのくらいのレベルなのか、気になるな。","ENG":"I'm curious if you're on an equal level with the Mansion's Assassin, whom I've only seen in documents.","TWN":"我很好奇，只在資料中看到過的曼森暗殺者，也就這個水準嗎。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"뭐, 수적인 열세에는 어쩔 수 없는 모양이지만.","JPN":"ま、数的な劣勢は仕方ないようだが。","ENG":"However, I guess you can't win being outnumbered.","TWN":"嗯，不過在數量上處於劣勢也是沒辦法的事。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"아하하, 그 언니는 사람 죽이는 재주가 죽이는 거고……","JPN":"あはは、あのお姉さんは、人を殺す才能がすごいけど……","ENG":"Ahahaha! That girl kills people because she's good at it.","TWN":"哈哈哈，因為那個姊姊殺人的手法一流……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"나는…… 콜록!","JPN":"アタシは……ゲホッ！","ENG":"I, on the other hand– *Cough!*","TWN":"而我……咳咳！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"괴물 죽이는 재주가 기똥찬 편이거든.","JPN":"怪物を殺す才能がすごいんだよね。","ENG":"Kill monsters because I'm damn good at it.","TWN":"則是殺怪物的手法比較棒。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"카운터도 아니면서 내가 손본 융합체들을 상대로 여기까지 버틴 건 칭찬해 주지.","JPN":"カウンターでもないくせに、私が手を加えた融合体を相手に、ここまで耐えたことは褒めてやろう。","ENG":"I must admit. I applaud you for lasting that long to my customized hybriders.","TWN":"明明不是制裁者，居然還能在我改造的融合體手下堅持到現在，這一點值得誇讚。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"너무 걱정 마시오. 사체를 해부해서 그 비결을 낱낱이 밝혀낼 테니.","JPN":"心配しなくてもいい。死体を解剖し、その秘訣を残さず突き止めよう。","ENG":"But don't you worry. I'll dissect your corpse and uncover all your little secrets.","TWN":"別擔心，我會解剖你的屍體，徹底查出這裡面的秘密。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"에엑, 해부대는 싫은데……","JPN":"げっ、解剖台はイヤだな……","ENG":"Eww... I don't like to be dissected...","TWN":"欸欸，我討厭解剖台……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그냥 순순히 털어 놓으면 안 될까?","JPN":"素直に話すのじゃダメ？","ENG":"How about I just tell you instead?","TWN":"我乖乖說出來不行嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"호오, 역시 단순히 미친 척 굴었던 건가.","JPN":"ほう、やはり単に狂人のふりをしていたのか。","ENG":"Ho-oh, so you were just pretending to be insane.","TWN":"哼，果然是在裝瘋賣傻嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"말할 기회는 주지. 그 범상치 않은 재주의 기원이 무엇이오?","JPN":"話す機会は与えてやろう。そのただならぬ才能の起源は何だ？","ENG":"Very well. I'll give you a chance to speak. So what is the secret to your unusual talent?","TWN":"我給你機會說出來。你那吧尋常的本領是怎麼來的？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"때는 1950년 언저리!","JPN":"時は1950年くらい！","ENG":"It all began around in 1950!","TWN":"大概是1950年吧！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"20세기라고? 연단술에 손을 대기라도 한 건가?","JPN":"20世紀だと？　錬丹術にでも手を出したのか？","ENG":"The 20th century? Are you saying you were involved in alchemy?!","TWN":"20世紀？你是碰了煉丹術嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"아니. 난 동료들과 함께 지구 정복을 위해 정찰하러 왔었어.","JPN":"ううん。アタシは仲間と一緒に、地球を征服するために偵察に来たんだよ。","ENG":"No. But my friends and I did come to scout earth before a conquest.","TWN":"不是，為了征服地球，我跟同伴們一起來地球偵察。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"미개한 인간들을 보면서 농담 따먹기를 하는 중이었지.","JPN":"未開の人間たちを見ながら冗談言ってた途中だったんだ。","ENG":"So we were basically joking around while watching humans do their thing.","TWN":"看著未開化的人類，我正在和他們開玩笑。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"헤이, 친구! 내 광선총 한 발이면 모조리 해치우고도 남겠는데?","JPN":"ヘイ、フレンド！　アタシの光線銃一発あれば全部殺せそうだね！","ENG":"\\"Hey! I think a blast of my laser gun will destroy them to bits, no?\\"","TWN":"嘿，朋友！我一槍就能把他們全都幹掉吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"……뭐?","JPN":"……何？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그런데 갑자기 항법 장치가 고장나는 바람에 기체가 지상으로 처박혀 버린 거야.","JPN":"でも、いきなり航法装置が壊れて機体が地上にめり込んじゃってさ。","ENG":"However, our navigation system failed, and our ship crash-landed to the ground.","TWN":"可是因為導航裝置突然壞掉，機體掉到了地面上。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"나는 낙하산으로 간신히 탈출했는데, 친구들은 폐활량이 모자라서 실패했지.","JPN":"アタシはパラシュートでやっと脱出したけど、友達は肺活量が足りなくて失敗したんだよ。","ENG":"I barely made it alive with my parachute, but all of my other friends failded due to a lack of vital capacity.","TWN":"我用降落傘好不容易逃了出來，隊友們卻因為肺活量不夠而失敗了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"구하러 찾아갔을 때는 인간 군인들이 잔뜩 몰려든 통에 포기해 버렸다고나 할까~","JPN":"助けに行った時には、人間の軍人たちがいっぱい来ていてあきらめちゃったっていうかさ～","ENG":"When I went to save them, the army was already there so I had to give up.","TWN":"我去救她們的時候，因為突然重出來一群人類軍人，我就放棄了～"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"이 빌어먹을 계집이……! 끝까지 학회를 우롱하는 건가!","JPN":"この女め……！　最後まで学会を愚弄するつもりか！","ENG":"You...! How dare you mock us to the bitter end?!","TWN":"你這個臭丫頭……！直到最後都在愚弄學會嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"아잉, 마저 들어 봐.","JPN":"いやん～、残りも聞いてよ。","ENG":"Hey, I'm not finished yet.","TWN":"哎呀，你接著聽啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"난 고향 별로 돌아가서 이 지옥 같은 행성을 테마파크로 보존하자고 할 거야.","JPN":"アタシは故郷に戻ってこの地獄みたいな星をテーマパークとして保存しようっていうつもりなんだ。","ENG":"Once I return to my home planet, I'm going to request that this stupid planet be preserved as an amusement park.","TWN":"如果我能返回故鄉星球，要把這個地獄般的行星當成主題公園來保存。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그럼 커다란 로켓처럼 콰광~ 하고 엄청난 폭발을 추진력 삼아 날아갈 수밖에 없잖아?","JPN":"だったら、大きなロケットみたいにドドーンって、すごい爆発を推進力にして飛んでいくしかないじゃない？","ENG":"Then it can be like a giant rocket that goes BOOOOOM!! and flies away, right?","TWN":"那就只能像巨大的火箭一樣，將巨大爆炸作為推進力飛走不是嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"잡소리는 끝이다. 이 미치광이야.","JPN":"くだらん話はお終いだ。この狂人。","ENG":"That's enough of your nonsense, you lunatic.","TWN":"廢話就到此為止吧，你這個瘋子。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L34_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"남은 이야기는 해부대 위에서 털어 놓으시지.","JPN":"続きは解剖台の上でやれ。","ENG":"I'll hear the rest when you're lying on the dissection table.","TWN":"剩下的話，可以留到解剖台上再說。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그래서 지하수로에 쌓아 뒀던 폭탄들을 잔뜩 욱여 넣었단 말씀.","JPN":"それで、積んでおいた爆弾を地下水路にいっぱい詰め込んだわけ。","ENG":"So, I'm just saying that I shoved a whole bunch of explosives into the underground waterway.","TWN":"所以我把堆積的炸彈全都放進了地下水道裡。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"영지 전체에 뻗어 있으니까 폭발도 그만큼 어마어마하겠지? 난 천재야!","JPN":"領地全体にわたってるから、爆発力も相当だろうね！　アタシって天才！","ENG":"And since that spreads throughout the estate, the explosion will be massive, right? See? I'm an absolute genius!","TWN":"因為水道遍佈整個領地，所以爆炸的威力也會同樣巨大吧？我真是天才。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"뭣이……? 허튼 수작을!","JPN":"何だと……？　くだらん手を！","ENG":"What...?! You're bluffing!","TWN":"什麼……？別耍花招！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"10~","JPN":"10～","ENG":"10...!","TWN":"10～"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"제정신이냐? 이 영지는 학회의 성지 같은 곳이다!","JPN":"正気なのか？　この領地は、学会の聖地も同然なんだぞ！","ENG":"Are you out of your mind?! The estate is holy ground for the Society!","TWN":"你瘋了嗎？這個領地是學會的聖地。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"9~","JPN":"9～","ENG":"9...!","TWN":"9～"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"안나 부인의 혼이 잠들어 있는 장소란 말이다!","JPN":"アンナ夫人の魂が眠っているところなのだ！","ENG":"It's Anna MacCready's resting place!","TWN":"是安娜夫人的靈魂安息的地方！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"꺄하하하하하하! 아저씨 표정 진짜 웃기다!","JPN":"キャハハハハハハ！　おじさんの顔、マジうける！","ENG":"KYAHAHAHAHA! You should see the look on your face right now!","TWN":"哈哈哈哈哈哈！大叔的表情真是太搞笑了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"앗. 근데 벌써 질렸어.","JPN":"あっ。でももう飽きちゃった。","ENG":"Oops. But I'm not interested in you, already.","TWN":"啊，不過我已經厭倦了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"뒈지기 싫으면 당장 멈춰!!","JPN":"死にたくなければ今すぐ止まれ！！","ENG":"STOP IT RIGHT NOW IF YOU WANT TO LIVE!!","TWN":"不想死的話，就馬上停下！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"뿌슝~!","JPN":"ピョーン！","ENG":"KABOOOOOOM!","TWN":"咻～！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"커헉……. 쿨럭……!","JPN":"ガハッ……ゴホッ……！","ENG":"Kuh...! *Cough...!*","TWN":"咳咳……咳咳……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"안 돼……. 영지가 불타다니, 맥크레디 영지가…….","JPN":"いかん……領地が燃えてしまう、マクレディー領地が……","ENG":"No... The MacCready Estate... It's up in flames...","TWN":"不要……領地著火了，麥克蕾蒂領地……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"찾아라!!","JPN":"探せ！！","ENG":"FIND HER!!","TWN":"快去找！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"그 미치광이를 찾아!","JPN":"あの狂人を探せ！","ENG":"FIND THAT LUNATIC!!","TWN":"找到那個瘋子！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"죽여 주지…! 이미 죽었어도 반드시 살려내서 내 손으로 다시 죽여 주마!","JPN":"殺してやる……！　すでに死んでいても必ず蘇らせ、私の手でまた殺してやる！","ENG":"I'll kill her myself...! If she's already dead, I'll revive her just so I can finish her off again!","TWN":"我要殺了你……！哪怕你已經死了，我也一定要把你救活，然後再親手殺了你！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"왜 그렇게 화를 내죠, 하이드리히 소장?","JPN":"なにをそんなに怒っているのですか？　ハイドリヒ所長。","ENG":"Why are you so angry, Chief Heydrich?","TWN":"你為什麼這麼生氣啊，海德里希所長？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"이 목소리는, 안나……?","JPN":"この声は、アンナ……？","ENG":"That voice... Is that Anna...?","TWN":"這個聲音是，安娜……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"맥크레디 영지는 제 소관일 텐데요.","JPN":"マクレディー領地は私の管轄であるはずです。","ENG":"The MacCready Estate under my jurisdiction, was it not?","TWN":"麥克蕾蒂領地應該歸我管轄吧。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CAMP_FIRE_LOOP"},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"지나친 관심은 그리 달갑지 않습니다. 사적인 감정이 섞여 있다면 더더욱 말이죠.","JPN":"度の過ぎた関心は困りますわ。。私的な感情が混ざっているならなおさら。","ENG":"I do not welcome excessive attention. Even more so if personal feelings are in the mix.","TWN":"我可不希望你過度關心。如果其中夾雜著私人感情，那就更不允許了。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"부학회장……","JPN":"副学会長……","ENG":"Vice President...","TWN":"副學會長……"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"흠. 확실히 내 실언이오. 소란이 일어났는데도 조용하시기에 부재 중인 줄 알았소.","JPN":"ふむ。確かに私の失言だった。衝動があったにも関わらず静かだったので、不在中だと思ったのだ。","ENG":"Ahem, my apologies. With all the commotion going on and no word from you, I assumed you were long gone.","TWN":"嗯，確實是我失言了。發生騷亂時也沒聽見你出聲，我還以為你不在呢。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"보아하니 몸가짐을 고치기 바빠서 못 알아챈 모양이군.","JPN":"みだしなみを整えることに夢中で気付かなかったようだな。","ENG":"But from the looks of it, you were busy getting dressed to notice.","TWN":"看樣子你剛才是一時慌亂吧，都沒認出我來。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"네. 에델을 만나러 가는 길이라 나름대로 채비를 갖췄죠.","JPN":"はい。エデルに会いに行くので、私なりに用意しました。","ENG":"Yes. I was getting prepared to meet with Edel.","TWN":"是啊，我正要去見艾瑟兒，所以自己做了一些準備。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"그래서, 리벳은 어디 있죠?","JPN":"それで、リベットはどこにいるのでしょうか。","ENG":"So? Where is Rivet?","TWN":"所以里維在哪？"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"그 미치광이라면 잔해 속에 파묻혀 버렸을 거요.","JPN":"あの狂人なら、残骸の下に埋められているだろう。","ENG":"That lunatic is buried somewhere with the rubble.","TWN":"那個瘋子應該埋在殘骸下面了。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"그리고 외람된 이야기지만……","JPN":"それに、僭越ながら……","ENG":"And with all due respect...","TWN":"而且，恕我冒昧……"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"이 상황의 태반은 부학회장이 고용한 그 외지인이 자초한 것일 터.","JPN":"この状態の大半は副学会長が雇ったよそ者が自ら招いたこと。","ENG":"The majority of this was caused by the outlander that you hired.","TWN":"這種情況大半是副學會長雇傭的那個外地人自找的。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"인선에 실책이 크다는 사실은 부정할 수 없겠구려. 아니 그렇소?","JPN":"人選を誤ったという事実は否定できない。違うか？","ENG":"It cannot be denied that you made a grave mistake in choosing the wrong personnel, no?","TWN":"你應該沒辦法否認自己選錯了人，不是嗎？"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"어느 정도 납득할 수 있는 지적이군요.","JPN":"ある程度納得できる指摘ですわね。","ENG":"A fair point.","TWN":"在某種程度上，我可以接受你的這種指責。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"권한도 정지된 자가, 외지인을 끌어들여 이 사달을 낸 것이오.","JPN":"権限も停止された者が、よそ者を引き入れてこのような事態を発生させたのだ。","ENG":"Someone who had lost their power hired an outsider, who was the one who made this mess.","TWN":"一個許可權被暫停的人，拉進來一個外地人，做出這種事。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"마땅히 그에 걸맞은 대가를 치러야지.","JPN":"それ相応の代償を払わねばなるまい。","ENG":"And that someone must pay for what she's done.","TWN":"當然應該付出相應的代價。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"생물학부장이 저에게 죄를 묻겠다는 건가요?","JPN":"生物学部長が私に罪を問うというのですか？","ENG":"Are you accusing me, Dean of Biology?","TWN":"生物學院院長是要追究我的責任嗎？"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"일개 학부장 주제에?","JPN":"一介の学部長のくせに？","ENG":"A lowly dean like yourself?","TWN":"就憑你區區一個學院院長？"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"절름발이 꼴로 허세를 부려 봤자 가엾기만 할 뿐이오, 부학회장.","JPN":"びっこを引いた姿で強がっても憐れに見えるだけだ、副学会長。","ENG":"Your bluffs, Vice President, are as pitiful as your limp.","TWN":"以你現在一瘸一拐的樣子，再怎麼虛張聲勢，也只會顯得更可憐而已，副學會長。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"애초에 네가 안나의 절반이라도 닮았다면, 이렇게 될 일도 없었겠지.","JPN":"そもそも君がアンナの半分くらいでも能力があったら、こうなることもなかっただろう。","ENG":"If you were as capable as only half of Anna, none of this would have happened.","TWN":"當初如果你能有一半像安娜，事情就不會變成現在這樣。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"자, 도망칠 수 없게 남은 다리만 마저 부러뜨릴 생각이오.","JPN":"さあ、逃げられないように残った足も折ってやろう。","ENG":"Now, I'm going to break your other leg so you can't run away anymore.","TWN":"好了，為了讓你沒辦法逃跑，我想打斷你剩下的那條腿。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"REPLACER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"한 번 겪었으니 두 번은 쉽게 참을 수 있겠지.","JPN":"一度経験したなら、二度目を耐えることなど訳無いだろう。","ENG":"I'm sure it won't be as bad of an experience as the first time.","TWN":"既然經歷過一次了，第二次應該會更容易忍受吧。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"REPLACER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"그 말이 맞습니다. 하이드리히 소장.","JPN":"そのとおりです。ハイドリヒ所長。","ENG":"You are precisely right, Chief Heydrich.","TWN":"你說的沒錯，海德里希所長。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"저는 어머니에 비해 힘도, 지략도. 권모술수도.","JPN":"私はお母様にくらべて力も、知略も、権謀術数も。","ENG":"In comparison to Mother, I lack her strength, resourcefulness, and manipulative abilities.","TWN":"和母親相比，或許我在力量、智謀、謀略……"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"모든 면에서 부족할지도 모르죠.","JPN":"すべての面で至らないかもしれません。","ENG":"Perhaps I lack in every way compared to her.","TWN":"甚至所有方面都遠不及她。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"그렇기에 제게 남은 것은 오직 하나.","JPN":"だからこそ、私に残されたのはたった一つ。","ENG":"All of that leaves me with one thing.","TWN":"所以，我就只剩下一個優勢，"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_ON","text":{"KOREA":"냉철한 이성뿐.","JPN":"冷徹な理性のみ。","ENG":"My cold-hearted reason.","TWN":"那就是冷靜的理智。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"뭐……? 그 시계는……?","JPN":"なっ……？　その時計は……？","ENG":"Huh...? That clock...","TWN":"什麼……？這個手錶是……？"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_ON","face":"UNIT_IDLE"},"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_ON","text":{"KOREA":"생물학부장, 하이드리히.","JPN":"生物学部長、ハイドリヒ。","ENG":"Dean of Biology, Heydrich.","TWN":"生物學院院長，海德里希。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_ON","face":"UNIT_IDLE"},"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_ON","text":{"KOREA":"정지하라.","JPN":"凍りなさい。","ENG":"Halt.","TWN":"停止吧。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_ON","face":"UNIT_IDLE"},"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};